[SRSReportParameterAttribute(classStr(ETG_InventFairValueReportContract))]
class ETG_InventFairValueReportDP extends SRSReportDataProviderBase
{
    ETG_InventFairValueHeaderTable          inventFairValueHeaderTable;
    ETG_InventFairValueLineTable            ETG_InventFairValueLineTable, ETG_InventFairValueLineTableLocal;
    ETG_FairValuationSerialNumber           FairValuationSerialNumber;
   // InventTable                           inventTableloc;
    NoYes                                   config,size,color,style,site,warehouse,location,batchnumber;


}

Method.Source:
[SRSReportDataSetAttribute(tablestr(ETG_InventFairValueLineTable))]
public ETG_InventFairValueLineTable getETG_InventFairValueLineTable()
{

    //select * from ETG_InventFairValueLineTable where (  ETG_InventFairValueLineTable.FairValuationSerialNumber == FairValuationSerialNumber);
    select * from ETG_InventFairValueLineTable;
   return ETG_InventFairValueLineTable;
}

public void processReport()
{

    ETG_InventFairValueReportContract contract;
   // contract.parmConfig=inventFairValueHeaderTable.Grade;
    ;
    contract                  = this.rdpDataContract ;
    FairValuationSerialNumber = contract.parmFairValuationSerialNumber();

    config                    = contract.parmConfig();
    size                      = contract.parmSize();
    color                     = contract.parmColor();
    style                     = contract.parmStyle();
    site                      = contract.parmSite();
    warehouse                 = contract.parmWarehouse();
    location                  = contract.parmLocation();
    batchnumber               = contract.parmBatchNumber();

    ETG_InventFairValueLineTable.setTmp();
    while select  * from ETG_InventFairValueLineTableLocal
        where (  ETG_InventFairValueLineTableLocal.FairValuationSerialNumber == FairValuationSerialNumber) 

    {

        ETG_InventFairValueLineTable.clear();
        ETG_InventFairValueLineTable.FairValuationSerialNumber = ETG_InventFairValueLineTableLocal.FairValuationSerialNumber;
        ETG_InventFairValueLineTable.ItemNumber                = ETG_InventFairValueLineTableLocal.ItemNumber;
        ETG_InventFairValueLineTable.Itemdimension             = ETG_InventFairValueLineTableLocal.Itemdimension;
        ETG_InventFairValueLineTable.InventColorId             = ETG_InventFairValueLineTableLocal.InventColorId;
        ETG_InventFairValueLineTable.InventSizeId              = ETG_InventFairValueLineTableLocal.InventSizeId;
        ETG_InventFairValueLineTable.InventStyleId             = ETG_InventFairValueLineTableLocal.InventStyleId;
        ETG_InventFairValueLineTable.ItemName                  = ETG_InventFairValueLineTableLocal.ItemName;
        ETG_InventFairValueLineTable.OriginalCost              = ETG_InventFairValueLineTableLocal.OriginalCost;
        ETG_InventFairValueLineTable.OriginalCostValue         = ETG_InventFairValueLineTableLocal.OriginalCostValue;
        ETG_InventFairValueLineTable.Quantity                  = ETG_InventFairValueLineTableLocal.Quantity;
        ETG_InventFairValueLineTable.configId                  = ETG_InventFairValueLineTableLocal.configId;
        ETG_InventFairValueLineTable.UnitId                    = ETG_InventFairValueLineTableLocal.UnitId; //InventTable::find( inventTableloc.ItemId).inventTableModuleInvent().UnitId;
        ETG_InventFairValueLineTable.wMSLocationId             = ETG_InventFairValueLineTableLocal.wMSLocationId;
        ETG_InventFairValueLineTable.FairRate                  = ETG_InventFairValueLineTableLocal.FairRate;
        ETG_InventFairValueLineTable.FairValue                 = ETG_InventFairValueLineTableLocal.FairValue ;
        ETG_InventFairValueLineTable.DifferenceValue           = ETG_InventFairValueLineTableLocal.DifferenceValue;
        ETG_InventFairValueLineTable.insert();


    }

}
